  ('social-worker-moex-00419', 'social-worker', 'social-worker-moex-113-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '若研究進行前完全告知參與者研究內容，研究便無法進行，此時關於研究倫理的敘述，下列何者 錯誤？', '["研究所涉及的風險必須非常低", "能在事前告知的資訊必須儘可能事前告知", "在研究程序結束後儘早將真相告知參與者，以獲得其理解", "研究主要為增進人類福祉，故參與者事後知情並不重要"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:03+00:00", "source_pdf_sha1": "deafa47b7c52", "answer_pdf_sha1": "89a468aadf0c", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "103", "s": "0306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
